class g{constructor(t,e){this.trackId=t,this.checkpoints=e,this._telemetry=null}loadFromObject(t){return!t||t.trackId!==this.trackId?(console.warn(`[TelemetryPlayer] trackId mismatch: expected "${this.trackId}", got "${t==null?void 0:t.trackId}"`),!1):(this._telemetry=t,console.log(`[TelemetryPlayer] Loaded telemetry for "${this.trackId}": ${t.segments.length} segments, ${t.segments.reduce((e,s)=>e+s.samples.length,0)} samples.`),!0)}get isLoaded(){return this._telemetry!==null}buildWaypoints(){if(!this._telemetry)return null;const t=[],e=this.checkpoints;for(const s of this._telemetry.segments){const l=e[s.fromCheckpoint%e.length],n=e[s.toCheckpoint%e.length];if(!l||!n)continue;const o=n.x-l.x,c=n.z-l.z,a=Math.sqrt(o*o+c*c),i=a>.001?c/a:0,h=a>.001?-o/a:0;for(const r of s.samples){const p=l.x+o*r.t+i*r.lateral,m=l.z+c*r.t+h*r.lateral;t.push({x:parseFloat(p.toFixed(3)),z:parseFloat(m.toFixed(3)),speed:r.speed,grip:r.grip??1})}}return console.log(`[TelemetryPlayer] Built ${t.length} world-space waypoints.`),t.length>0?t:null}}export{g as TelemetryPlayer};
